const S={data:null,page:'dashboard',month:'',masked:localStorage.getItem(K.mask)==='1',txnExpanded:false,txnPage:0,sort:'date',filters:{type:'',account:'',category:''},charts:{},busy:false,syncing:false,theme:localStorage.getItem(K.theme)||'system',holdingFilter:'all'};
