async function saveSnapshot(month){if(!monthHasEnded(month))return toast('Month-end snapshot is available only after the selected month has ended.');if(!readyToClose(month))return toast('Required month-end balance and valuation inputs are still pending.');const status=canConfirmMonth(month)?'confirmed_closed':'provisional_closed';const label=status==='confirmed_closed'?'Confirmed Closed':'Provisional Closed';if(!confirm(`Save ${monthLabel(month)} as ${label} snapshot?`))return;const rows=estimateHoldingRows(month).map(r=>({instrument_id:r.instrument_id,amount:r.amount,value_basis:r.value_basis,notes:'Saved from app month-end workflow'}));await actionAndRefresh($('snapshotBtn'),'saveMonthSnapshot',{reporting_month:month,status,rows},'Saving…',`${label} month-end snapshot saved and synced.`)}
