function drawForecast(f){if(!window.Chart)return;const actualMonths=closedMonths(), actualValues=actualMonths.map(snapshotTotal);const labels=[...new Set([...actualMonths,...f.baseline.map(x=>x.month)])];const pad=a=>labels.map(m=>a.find(x=>x.month===m)?.value??null);S.charts.forecast=new Chart($('forecastChart'),{type:'line',data:{labels:labels.map(monthLabel),datasets:[{label:'Actual Portfolio Value',data:labels.map(m=>actualMonths.includes(m)?snapshotTotal(m):null),borderColor:'#1767a6',backgroundColor:'#1767a6',tension:.25,spanGaps:false},{label:'Regular Baseline Forecast',data:pad([{month:f.start,value:snapshotTotal(f.start)},...f.baseline]),borderColor:'#d89c32',borderDash:[7,5],tension:.25,spanGaps:true},{label:'Updated Forecast',data:pad([{month:f.start,value:snapshotTotal(f.start)},...f.current]),borderColor:'#059c94',borderDash:[4,4],tension:.25,spanGaps:true}]},options:{responsive:true,maintainAspectRatio:false,plugins:{tooltip:{callbacks:{label:c=>S.masked?`${c.dataset.label}: Rp ••••••`:`${c.dataset.label}: ${compact(c.raw)}`}},legend:{position:'bottom'}},scales:{y:{ticks:{callback:v=>S.masked?'••':compactAxis(v)}}}}})}
function configureAdaptiveDetails(){const mobile=window.matchMedia('(max-width:719px)').matches;qa('.adaptive-details').forEach(d=>{d.open=!mobile})}

function drawSpending(exp){if(!window.Chart||!$('spendingChart'))return;let list=exp.list,small=list.filter(x=>x.share<3),large=list.filter(x=>x.share>=3);if(small.length)large.push({category:'other_grouped',amount:small.reduce((s,x)=>s+x.amount,0),share:small.reduce((s,x)=>s+x.share,0)});const sliceLabels={id:'sliceLabels',afterDatasetsDraw(chart){if(S.masked)return;const meta=chart.getDatasetMeta(0),total=large.reduce((s,x)=>s+x.amount,0),ctx=chart.ctx;ctx.save();ctx.fillStyle='#fff';ctx.font='700 12px Inter, Segoe UI, Arial';ctx.textAlign='center';ctx.textBaseline='middle';meta.data.forEach((arc,i)=>{const share=total?large[i].amount/total*100:0;if(share<4)return;const p=arc.tooltipPosition();ctx.fillText(`${share.toFixed(0)}%`,p.x,p.y)});ctx.restore()}};S.charts.spending=new Chart($('spendingChart'),{type:'doughnut',data:{labels:large.map(x=>x.category==='other_grouped'?'Other':displayCat(x.category)),datasets:[{data:large.map(x=>x.amount),backgroundColor:['#1767a6','#059c94','#d89c32','#7664d8','#e86965','#7a93a7','#2cbd98','#f0c15c']}]},plugins:[sliceLabels],options:{responsive:true,maintainAspectRatio:false,cutout:'57%',plugins:{legend:{position:'bottom',labels:{boxWidth:12,usePointStyle:true}},tooltip:{callbacks:{label:c=>S.masked?`${c.label}: •••%`:`${c.label}: ${(large[c.dataIndex].share).toFixed(1)}%`}}}}})}

function destroyCharts(){Object.values(S.charts).forEach(c=>{try{c.destroy()}catch{}});S.charts={}}
document.addEventListener('click',touchSession);document.addEventListener('keydown',touchSession);document.addEventListener('touchstart',touchSession,{passive:true});document.addEventListener('mousemove',touchSession,{passive:true});document.addEventListener('visibilitychange',()=>{if(document.hidden&&isUnlocked())sessionStorage.setItem(K.away,String(Date.now()));else if(!document.hidden){const away=Date.now()-Number(sessionStorage.getItem(K.away)||0);if(away>AWAY_MS)lock()}});window.addEventListener('online',()=>backgroundSync(true));
if(window.matchMedia)window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change',()=>{if(S.theme==='system'){applyTheme();if(S.data&&isUnlocked())renderApp()}});
window.addEventListener('load',()=>{applyTheme();if('serviceWorker' in navigator)navigator.serviceWorker.register('./service-worker.js').catch(()=>{});const cached=getCache();if(cached&&localStorage.getItem(K.pin)){S.data=cached;S.month=currentAnalysisMonth();if(isUnlocked()){renderApp();backgroundSync(true)}else renderLock()}else renderPublic()});
